/*
* You can use any libraries imported in Autonomous
* You can use properties specified in Input Variables with the prefix $. For example: $foo
* You can get default flow config: $flow.sessionId, $flow.chatId, $flow.chatflowId, $flow.input, $flow.state
* You can get global variables: $vars.<variable-name>
* Must return a string value at the end of function
*/

const fetch = require('node-fetch');
const url = 'https://api.open-meteo.com/v1/forecast?latitude=52.52&longitude=13.41&current_weather=true';
const options = {
    method: 'GET',
    headers: {
        'Content-Type': 'application/json'
    }
};
try {
    const response = await fetch(url, options);
    const text = await response.text();
    return text;
} catch (error) {
    console.error(error);
    return '';
}

inputs.customFunctionJavascriptFunction:
/*
 * SINGLE Custom Function:
 * 1) Parse quiz JSON from $input (Agent1 output)
 * 2) POST to Apps Script WebApp (create form)
 * 3) Store links in $flow.state.attendLink / $flow.state.editLink
 * 4) Return "" so NOTHING prints before Human Input
 */

const fetch = require("node-fetch");

const WEBAPP_URL = String($webappUrl || "").trim(); // set in Flowise Variables
if (!WEBAPP_URL) return "❌ Missing variable: webappUrl";

function parseAnyJson(input) {
  let raw =
    typeof input === "string"
      ? input
      : input && typeof input === "object"
      ? JSON.stringify(input)
      : String(input || "");

  raw = raw.trim();
  raw = raw.replace(/```(?:json)?/gi, "").replace(/```/g, "").trim();

  // direct parse
  try {
    return JSON.parse(raw);
  } catch (e) {}

  // extract { ... }
  const s = raw.indexOf("{");
  const e = raw.lastIndexOf("}");
  if (s !== -1 && e !== -1 && e > s) {
    return JSON.parse(raw.slice(s, e + 1));
  }

  throw new Error("No valid JSON found in Agent output");
}

try {
  // 1) quiz json from Agent1
  const quiz = parseAnyJson($input);

  // 2) create google form via Apps Script
  const res = await fetch(WEBAPP_URL, {
    method: "POST",
    headers: { "Content-Type": "application/json" },
    body: JSON.stringify(quiz),
  });

  const text = await res.text();
  let data;
  try {
    data = JSON.parse(text);
  } catch (e) {
    return `❌ WebApp returned non-JSON: ${text.slice(0, 200)}`;
  }

  // 3) extract links (your webapp may use different keys)
  const attend =
    data.attendUrl || data.attendLink || data.viewUrl || data.attendanceLink;
  const edit = data.editUrl || data.editLink || data.editorLink;

  if (!attend) return `❌ attend link missing in webapp response: ${text}`;
  if (!edit) return `❌ edit link missing in webapp response: ${text}`;

  // store in state for Agent0
  $flow.state.attendLink = String(attend);
  $flow.state.editLink = String(edit);

  // 4) IMPORTANT: hide output before Human Input
  return "";
} catch (err) {
  return `❌ Error: ${String(err.message || err)}`;
}

